#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        if ((A ^ B) == 0) {
            printf("Vanka\n");
        } else {
            printf("Tuzik\n");
        }
    }
    return 0;
}

